import numpy as np
from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector

a = QuantumCircuit(1); a.x(0)
b = QuantumCircuit(1); b.id(0)
combined = a.tensor(b)
sv = Statevector(combined).data
nz = {format(i, "02b"): sv[i] for i in range(4) if abs(sv[i]) > 1e-9}

def is_single(state):
    return set(nz) == {state} and np.isclose(nz[state], 1.0)

claims = {
    "A": is_single("01"),
    "B": is_single("11"),
    "C": len(nz) == 4,
    "D": is_single("10"),
}
nzr = {k: str(np.round(v, 3)) for k, v in nz.items()}
evidence = {
    "A": f"nonzero amplitudes={nzr}; claim |01> -> {claims['A']}",
    "B": f"nonzero={nzr}; claim |11> -> {claims['B']}",
    "C": f"nonzero={nzr} ({len(nz)} states); claim superposition -> {claims['C']}",
    "D": f"nonzero={nzr}; single |10> (a on high qubit) -> {claims['D']}",
}
proven = [k for k, v in claims.items() if v]
emit_verdict({"answer": proven, "evidence": evidence, "observed": {"nonzero": nzr}})
